#include <bits/stdc++.h>
using namespace std;
string c;
int main(){
    int n,g=0;
    cin>>n;
    string a[n][2],b;
    for(int i=0;i<n;i++){
        cin>>a[i][0]>>a[i][1];
    }
    cin>>b;
    for(int i=0;i<=b.size();i++){
        if('a'<=b[i]&&b[i]<='z'){
            c+=b[i];
        }
        else{
        	g=0;
            for(int j=0;j<n;j++){
                if(c==a[j][0]){
                    cout<<a[j][1];
                    g=1;
                    break;
                }
            }
            if(g==0&&c!=""){
				cout<<"UNK";
			}
            c.clear();
            cout<<b[i];
        }
    }
    return 0;
}
